# React Expandable Text Component

> [!TIP] Description
> A UI component that handles long text or JSON content with a "Show More/Less" toggle. Includes a gradient fade-out effect for the collapsed state.

```tsx
const ExpandableContent = ({ content, isJson = false, textThreshold = 500 }) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const shouldTruncate = content.length > textThreshold;

  return (
    <div className="relative">
      <div className={`transition-all duration-500 ${!isExpanded ? "max-h-[300px]" : "max-h-full"}`}>
        {content}
        {shouldTruncate && !isExpanded && (
          <div className="absolute bottom-0 left-0 right-0 h-24 bg-gradient-to-t from-secondary/20 to-transparent" />
        )}
      </div>

      {shouldTruncate && (
        <button onClick={() => setIsExpanded(!isExpanded)}>
          {isExpanded ? "Show less" : "Show more"}
        </button>
      )}
    </div>
  );
};
```

